use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

struct LogEntry {
    key: String,
    value: String,
}

fn main() {
    let log_buffer: Arc<Mutex<VecDeque<LogEntry>>> = Arc::new(Mutex::new(VecDeque::new()));

    let process_entry = |log_buffer: &Arc<Mutex<VecDeque<LogEntry>>>, _key: &str, _value: &str| {
        match log_buffer.lock().unwrap().pop_front() {
            Some(entry) => {
                println!("Processed item: {}: {}", entry.key, entry.value);
            }
            None => {
                println!("No entries available to process.");
            }
        }
    };

    let mut buffer = log_buffer.lock().unwrap();
    buffer.push_back(LogEntry { key: String::from("user_1"), value: String::from("initial_data") });
    buffer.push_back(LogEntry { key: String::from("config"), value: String::from("version_a") });
    buffer.push_back(LogEntry { key: String::from("user_2"), value: String::from("temp_data") });
    drop(buffer);

    let log_clone = Arc::clone(&log_buffer);
    process_entry(&log_clone, "", "");

    let log_clone = Arc::clone(&log_buffer);
    process_entry(&log_clone, "", "");

    let log_clone = Arc::clone(&log_buffer);
    process_entry(&log_clone, "", "");
}

use std::collections::HashMap;

#[derive(Debug)]
pub struct TelemetryRecord {
    pub device_id: String,
    pub timestamp: i64,
    pub data: HashMap<String, String>,
}

fn process_logs(records: Vec<TelemetryRecord>) {
    for record in records {
        let severity = record.data.get("severity");

        if let Some(s) = severity {
            if s == "CRITICAL" {
                println!("ALERT TRIGGERED for device {} at timestamp {}", record.device_id, record.timestamp);
            } else if s == "WARNING" {
                println!("INFO: Passing through non-critical warning from device {}", record.device_id);
            }
        }
    }
}

use std::cmp::max;

struct AlignmentResult {
    score: i32,
    aligned_seq1: String,
    aligned_seq2: String,
}

fn smith_waterman(matrix: &[Vec<i32>], seq1: &str, seq2: &str) -> AlignmentResult {
    let m = seq1.len();
    let n = seq2.len();
    let mut dp = vec![vec![0; n + 1]; m + 1];

    for i in 1..=m {
        for j in 1..=n {
            let match_val = if seq1.chars().nth(i - 1).unwrap() == seq2.chars().nth(j - 1).unwrap() { 2 } else { -1 };
            dp[i][j] = max(0,
                max(dp[i - 1][j - 1] + match_val, 
                    std::cmp::max(dp[i - 1][j] + (-2), dp[i][j - 1] + (-2)))
            );
        }
    }

    let mut score = 0;
    let mut i = m;
    let mut j = n;

    while i > 0 && j > 0 {
        if dp[i][j] == 0 { break; }
        score = dp[i][j];
        i -= 1;
        j -= 1;
    }

    AlignmentResult {
        score: score,
        aligned_seq1: String::new(), 
        aligned_seq2: String::new()
    }
}

use std::collections::VecDeque;

struct ConnectionState {
    is_connected: bool,
    event_history: VecDeque<String>,
}

impl ConnectionState {
    fn new() -> Self {
        ConnectionState {
            is_connected: false,
            event_history: VecDeque::new(),
        }
    }
}

fn process_network_event(state: &mut ConnectionState, event: &str) -> bool {
    if state.is_connected && !event.contains("disconnected") {
        let msg = format!("Network stable: {}", event);
        state.event_history.push_back(msg);
        return true;
    }

    match event.contains("reconnected") {
        true => {
            if !state.is_connected {
                println!("Transitioned to connected state.");
                state.is_connected = true;
                let msg = format!("Successfully reconnected at {}", event);
                state.event_history.push_back(msg);
                return true;
            }
        }
        false => {
            if state.is_connected && event.contains("disconnected") {
                println!("Transitioned to disconnected state.");
                state.is_connected = false;
                let msg = format!("Lost connection: {}", event);
                state.event_history.push_back(msg);
                return true;
            }
        }
    }
    false
}

fn main() {
    let mut state = ConnectionState::new();
    println!("Initial State: {}", state.is_connected);

    process_network_event(&mut state, "initial_check");
    println!("After check 1: Connected={}", state.is_connected);

    process_network_event(&mut state, "reconnected successfully");
    println!("After reconnect: Connected={}", state.is_connected);

    process_network_event(&mut state, "background activity update");
    println!("History size after stable event: {}", state.event_history.len());

    process_network_event(&mut state, "disconnected due to timeout");
    println!("After disconnect: Connected={}", state.is_connected);

    process_network_event(&mut state, "reconnected again");
    println!("Final History Size: {}", state.event_history.len());
}

use std::collections::HashMap;

struct GameEvent {
    timestamp: u64,
    eventType: String,
    playerState: String,
    payload: HashMap<String, String>,
}

fn process_replay(events: Vec<GameEvent>) -> Vec<String> {
    let mut processed_results = Vec::new();
    for event in events {
        match event.playerState.as_str() {
            "active" => {
                if let Some(score) = event.payload.get("score") {
                    processed_results.push(format!("Processed active event at {}: Score {}", event.timestamp, score));
                }
            },
            "loading" => {
                println!("Skipping loading state event.");
            },
            _ => {
                println!("Unknown state encountered: {}", event.playerState);
            }
        }
    }
    processed_results
}

fn main() {
    let mut payload1 = HashMap::new();
    payload1.insert("score".to_string(), "90".to_string());

    let mut payload2 = HashMap::new();
    payload2.insert("source".to_string(), "network".to_string());

    let events = vec![ 
        GameEvent { timestamp: 100, eventType: "move".to_string(), playerState: "active".to_string(), payload: payload1.clone() },
        GameEvent { timestamp: 250, eventType: "wait".to_string(), playerState: "loading".to_string(), payload: HashMap::new() },
        GameEvent { timestamp: 300, eventType: "hit".to_string(), playerState: "active".to_string(), payload: HashMap::new() },
        GameEvent { timestamp: 400, eventType: "error".to_string(), playerState: "disconnected".to_string(), payload: payload2.clone() },
    ];

    let results = process_replay(events);
    for result in results {
        println!("Final Output: {}", result);
    }
}
